INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Acid Splash', 0, 'Evocation', 'Action', '60 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Sorcerer', 'Wizard']::TEXT[], 'You create an acidic bubble at a point within range, where it explodes in a 5-foot-radius Sphere. Each creature in that Sphere must succeed on a Dexterity saving throw or take 1d6 Acid damage.', 'Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', FALSE, ARRAY['artificer', 'cantrip', 'evocation', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Dancing Lights', 0, 'Illusion', 'Action', '120 feet', 'V, S, M (a bit of phosphorus)', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Sorcerer', 'Wizard']::TEXT[], 'You create up to four torch-size lights within range, making them appear as torches, lanterns, or glowing orbs that hover for the duration. Alternatively, you combine the four lights into one glowing Medium form that is vaguely humanlike. Whichever form you choose, each light sheds Dim Light in a 10-foot radius.

As a Bonus Action, you can move the lights up to 60 feet to a space within range. A light must be within 20 feet of another light created by this spell, and a light vanishes if it exceeds the spell’s range.', NULL, FALSE, ARRAY['artificer', 'bard', 'cantrip', 'illusion', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Blade Ward', 0, 'Abjuration', 'Action', 'Self', 'V, S', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Bard', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'Whenever a creature makes an attack roll against you before the spell ends, the attacker subtracts 1d4 from the attack roll.', NULL, FALSE, ARRAY['abjuration', 'bard', 'cantrip', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Druidcraft', 0, 'Transmutation', 'Action', '30 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Druid']::TEXT[], 'Whispering to the spirits of nature, you create one of the following effects within range.

Weather Sensor. You create a Tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. The effect might manifest as a golden orb for clear skies, a cloud for rain, falling snowflakes for snow, and so on. This effect persists for 1 round.

Bloom. You instantly make a flower blossom, a seed pod open, or a leaf bud bloom.

Sensory Effect. You create a harmless sensory effect, such as falling leaves, spectral dancing fairies, a gentle breeze, the sound of an animal, or the faint odor of skunk. The effect must fit in a 5-foot Cube.

Fire Play. You light or snuff out a candle, a torch, or a campfire.', NULL, FALSE, ARRAY['cantrip', 'druid', 'transmutation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Chill Touch', 0, 'Necromancy', 'Action', 'Touch', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'Channeling the chill of the grave, make a melee spell attack against a target within reach. On a hit, the target takes 1d10 Necrotic damage, and it can’t regain Hit Points until the end of your next turn.', 'Cantrip Upgrade. The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).', FALSE, ARRAY['cantrip', 'necromancy', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Eldritch Blast', 0, 'Evocation', 'Action', '120 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Warlock']::TEXT[], 'You hurl a beam of crackling energy. Make a ranged spell attack against one creature or object in range. On a hit, the target takes 1d10 Force damage.', 'Cantrip Upgrade. The spell creates two beams at level 5, three beams at level 11, and four beams at level 17. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.', FALSE, ARRAY['cantrip', 'evocation', 'warlock']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Elementalism', 0, 'Transmutation', 'Action', '30 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Druid', 'Sorcerer', 'Wizard']::TEXT[], 'You exert control over the elements, creating one of the following effects within range.

Beckon Air. You create a breeze strong enough to ripple cloth, stir dust, rustle leaves, and close open doors and shutters, all in a 5-foot Cube. Doors and shutters being held open by someone or something aren’t affected.

Beckon Earth. You create a thin shroud of dust or sand that covers surfaces in a 5-foot-square area, or you cause a single word to appear in your handwriting in a patch of dirt or sand.

Beckon Fire. You create a thin cloud of harmless embers and colored, scented smoke in a 5-foot Cube. You choose the color and scent, and the embers can light candles, torches, or lamps in that area. The smoke’s scent lingers for 1 minute.

Beckon Water. You create a spray of cool mist that lightly dampens creatures and objects in a 5-foot Cube. Alternatively, you create 1 cup of clean water either in an open container or on a surface, and the water evaporates in 1 minute.

Sculpt Element. You cause dirt, sand, fire, smoke, mist, or water that can fit in a 1-foot Cube to assume a crude shape (such as that of a creature) for 1 hour.', NULL, FALSE, ARRAY['artificer', 'cantrip', 'druid', 'sorcerer', 'transmutation', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Friends', 0, 'Enchantment', 'Action', '10 feet', 'S, M (some makeup)', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Bard', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You magically emanate a sense of friendship toward one creature you can see within range. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target succeeds automatically if it isn’t a Humanoid, if you’re fighting it, or if you have cast this spell on it within the past 24 hours.

The spell ends early if the target takes damage or if you make an attack roll, deal damage, or force anyone to make a saving throw. When the spell ends, the target knows it was Charmed by you.', NULL, FALSE, ARRAY['bard', 'cantrip', 'enchantment', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Fire Bolt', 0, 'Evocation', 'Action', '120 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Sorcerer', 'Wizard']::TEXT[], 'You hurl a mote of fire at a creature or an object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Fire damage. A flammable object hit by this spell starts burning if it isn’t being worn or carried.', 'Cantrip Upgrade. The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).', FALSE, ARRAY['artificer', 'cantrip', 'evocation', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Guidance', 0, 'Divination', 'Action', 'Touch', 'V, S', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Cleric', 'Druid']::TEXT[], 'You touch a willing creature and choose a skill. Until the spell ends, the creature adds 1d4 to any ability check using the chosen skill.', NULL, FALSE, ARRAY['artificer', 'cantrip', 'cleric', 'divination', 'druid']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Light', 0, 'Evocation', 'Action', 'Touch', 'V, M (a firefly or phosphorescent moss)', '1 hour', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Cleric', 'Sorcerer', 'Wizard']::TEXT[], 'You touch one Large or smaller object that isn’t being worn or carried by someone else. Until the spell ends, the object sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The light can be colored as you like.

Covering the object with something opaque blocks the light. The spell ends if you cast it again.', NULL, FALSE, ARRAY['artificer', 'bard', 'cantrip', 'cleric', 'evocation', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Mage Hand', 0, 'Conjuration', 'Action', '30 feet', 'V, S', '1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.

When you cast the spell, you can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial.

As a Magic action on your later turns, you can control the hand thus again. As part of that action, you can move the hand up to 30 feet.

The hand can’t attack, activate magic items, or carry more than 10 pounds.', NULL, FALSE, ARRAY['artificer', 'bard', 'cantrip', 'conjuration', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Mending', 0, 'Transmutation', '1 minute', 'Touch', 'V, S, M (two lodestones)', 'Instantaneous', 'Player''s Handbook', ARRAY['Bard', 'Cleric', 'Druid', 'Sorcerer', 'Wizard']::TEXT[], 'This spell repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot in any dimension, you mend it, leaving no trace of the former damage.

This spell can physically repair a magic item, but it can’t restore magic to such an object.', NULL, FALSE, ARRAY['bard', 'cantrip', 'cleric', 'druid', 'sorcerer', 'transmutation', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Mind Sliver', 0, 'Enchantment', 'Action', '60 feet', 'V', '1 round', 'Player''s Handbook', ARRAY['Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You try to temporarily sliver the mind of one creature you can see within range. The target must succeed on an Intelligence saving throw or take 1d6 Psychic damage and subtract 1d4 from the next saving throw it makes before the end of your next turn.', 'Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', FALSE, ARRAY['cantrip', 'enchantment', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Message', 0, 'Transmutation', 'Action', '120 feet', 'S, M (a copper wire)', '1 round', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Druid', 'Sorcerer', 'Wizard']::TEXT[], 'You point toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear.

You can cast this spell through solid objects if you are familiar with the target and know it is beyond the barrier. Magical silence; 1 foot of stone, metal, or wood; or a thin sheet of lead blocks the spell.', NULL, FALSE, ARRAY['artificer', 'bard', 'cantrip', 'druid', 'sorcerer', 'transmutation', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Minor Illusion', 0, 'Illusion', 'Action', '30 feet', 'S, M (a bit of fleece)', '1 minute', 'Player''s Handbook', ARRAY['Bard', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You create a sound or an image of an object within range that lasts for the duration. See the descriptions below for the effects of each. The illusion ends if you cast this spell again.

If a creature takes a Study action to examine the sound or image, the creature can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the illusion becomes faint to the creature.

Sound. If you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else’s voice, a lion’s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.

Image. If you create an image of an object—such as a chair, muddy footprints, or a small chest—it must be no larger than a 5-foot Cube. The image can’t create sound, light, smell, or any other sensory effect. Physical interaction with the image reveals it to be an illusion, since things can pass through it.', NULL, FALSE, ARRAY['bard', 'cantrip', 'illusion', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Prestidigitation', 0, 'Transmutation', 'Action', '10 feet', 'V, S', 'Up to 1 hour', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You create a magical effect within range. Choose the effect from the options below. If you cast this spell multiple times, you can have up to three of its non-instantaneous effects active at a time.

Sensory Effect. You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor.

Fire Play. You instantaneously light or snuff out a candle, a torch, or a small campfire.

Clean or Soil. You instantaneously clean or soil an object no larger than 1 cubic foot.

Minor Sensation. You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour.

Magic Mark. You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour.

Minor Creation. You create a nonmagical trinket or an illusory image that can fit in your hand. It lasts until the end of your next turn. A trinket can deal no damage and has no monetary worth.', NULL, FALSE, ARRAY['artificer', 'bard', 'cantrip', 'sorcerer', 'transmutation', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Poison Spray', 0, 'Necromancy', 'Action', '30 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Druid', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You spray toxic mist at a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d12 Poison damage.', 'Cantrip Upgrade. The damage increases by 1d12 when you reach levels 5 (2d12), 11 (3d12), and 17 (4d12).', FALSE, ARRAY['artificer', 'cantrip', 'druid', 'necromancy', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Produce Flame', 0, 'Conjuration', 'Bonus Action', 'Self', 'V, S', '10 minutes', 'Player''s Handbook', ARRAY['Druid']::TEXT[], 'A flickering flame appears in your hand and remains there for the duration. While there, the flame emits no heat and ignites nothing, and it sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. The spell ends if you cast it again.

Until the spell ends, you can take a Magic action to hurl fire at a creature or an object within 60 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 Fire damage.', 'Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', FALSE, ARRAY['cantrip', 'conjuration', 'druid']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Ray of Frost', 0, 'Evocation', 'Action', '60 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Sorcerer', 'Wizard']::TEXT[], 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 Cold damage, and its Speed is reduced by 10 feet until the start of your next turn.', 'Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', FALSE, ARRAY['artificer', 'cantrip', 'evocation', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Resistance', 0, 'Abjuration', 'Action', 'Touch', 'V, S', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Cleric', 'Druid']::TEXT[], 'You touch a willing creature and choose a damage type: Acid, Bludgeoning, Cold, Fire, Lightning, Necrotic, Piercing, Poison, Radiant, Slashing, or Thunder. When the creature takes damage of the chosen type before the spell ends, the creature reduces the total damage taken by 1d4. A creature can benefit from this spell only once per turn.', NULL, FALSE, ARRAY['abjuration', 'artificer', 'cantrip', 'cleric', 'druid']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Shillelagh', 0, 'Transmutation', 'Bonus Action', 'Self', 'V, S, M (mistletoe)', '1 minute', 'Player''s Handbook', ARRAY['Druid']::TEXT[], 'A Club or Quarterstaff you are holding is imbued with nature’s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon’s damage die becomes a d8. If the attack deals damage, it can be Force damage or the weapon’s normal damage type (your choice).

The spell ends early if you cast it again or if you let go of the weapon.', 'Cantrip Upgrade. The damage die changes when you reach levels 5 (d10), 11 (d12), and 17 (2d6).', FALSE, ARRAY['cantrip', 'druid', 'transmutation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Sacred Flame', 0, 'Evocation', 'Action', '60 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Cleric']::TEXT[], 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 Radiant damage. The target gains no benefit from Half Cover or Three-Quarters Cover for this save.', 'Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', FALSE, ARRAY['cantrip', 'cleric', 'evocation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Sorcerous Burst', 0, 'Evocation', 'Action', '120 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Sorcerer']::TEXT[], 'You cast sorcerous energy at one creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d8 damage of a type you choose: Acid, Cold, Fire, Lightning, Poison, Psychic, or Thunder.

If you roll an 8 on a d8 for this spell, you can roll another d8, and add it to the damage. When you cast this spell, the maximum number of these d8s you can add to the spell’s damage equals your spellcasting ability modifier.', 'Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', FALSE, ARRAY['cantrip', 'evocation', 'sorcerer']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Shocking Grasp', 0, 'Evocation', 'Action', 'Touch', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Sorcerer', 'Wizard']::TEXT[], 'Lightning springs from you to a creature that you try to touch. Make a melee spell attack against the target. On a hit, the target takes 1d8 Lightning damage, and it can’t make Opportunity Attacks until the start of its next turn.', 'Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', FALSE, ARRAY['artificer', 'cantrip', 'evocation', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Spare the Dying', 0, 'Necromancy', 'Action', '15 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Cleric', 'Druid']::TEXT[], 'Choose a creature within range that has 0 Hit Points and isn’t dead. The creature becomes Stable.', 'Cantrip Upgrade. The range doubles when you reach levels 5 (30 feet), 11 (60 feet), and 17 (120 feet).', FALSE, ARRAY['artificer', 'cantrip', 'cleric', 'druid', 'necromancy']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Starry Wisp', 0, 'Evocation', 'Action', '60 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Bard', 'Druid']::TEXT[], 'You launch a mote of light at one creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d8 Radiant damage, and until the end of your next turn, it emits Dim Light in a 10-foot radius and can’t benefit from the Invisible condition.', 'Cantrip Upgrade. The damage increases by 1d8 when you reach levels 5 (2d8), 11 (3d8), and 17 (4d8).', FALSE, ARRAY['bard', 'cantrip', 'druid', 'evocation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Thaumaturgy', 0, 'Transmutation', 'Action', '30 feet', 'V', 'Up to 1 minute', 'Player''s Handbook', ARRAY['Cleric']::TEXT[], 'You manifest a minor wonder within range. You create one of the effects below within range. If you cast this spell multiple times, you can have up to three of its 1-minute effects active at a time.

Altered Eyes. You alter the appearance of your eyes for 1 minute.

Booming Voice. Your voice booms up to three times as loud as normal for 1 minute. For the duration, you have Advantage on Charisma (Intimidation) checks.

Fire Play. You cause flames to flicker, brighten, dim, or change color for 1 minute.

Invisible Hand. You instantaneously cause an unlocked door or window to fly open or slam shut.

Phantom Sound. You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers.

Tremors. You cause harmless tremors in the ground for 1 minute.', NULL, FALSE, ARRAY['cantrip', 'cleric', 'transmutation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Thorn Whip', 0, 'Transmutation', 'Action', '30 feet', 'V, S, M (the stem of a thorny plant)', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Druid']::TEXT[], 'You create a vine-like whip covered in thorns that lashes out at your command toward a creature in range. Make a melee spell attack against the target. On a hit, the target takes 1d6 Piercing damage, and if it is Large or smaller, you can pull it up to 10 feet closer to you.', 'Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', FALSE, ARRAY['artificer', 'cantrip', 'druid', 'transmutation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Thunderclap', 0, 'Evocation', 'Action', 'Self', 'S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Druid', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'Each creature in a 5-foot Emanation originating from you must succeed on a Constitution saving throw or take 1d6 Thunder damage. The spell’s thunderous sound can be heard up to 100 feet away.', 'Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', FALSE, ARRAY['artificer', 'bard', 'cantrip', 'druid', 'evocation', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Toll the Dead', 0, 'Necromancy', 'Action', '60 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Cleric', 'Warlock', 'Wizard']::TEXT[], 'You point at one creature you can see within range, and the single chime of a dolorous bell is audible within 10 feet of the target. The target must succeed on a Wisdom saving throw or take 1d8 Necrotic damage. If the target is missing any of its Hit Points, it instead takes 1d12 Necrotic damage.', 'Cantrip Upgrade. The damage increases by one die when you reach levels 5 (2d8 or 2d12), 11 (3d8 or 3d12), and 17 (4d8 or 4d12).', FALSE, ARRAY['cantrip', 'cleric', 'necromancy', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('True Strike', 0, 'Divination', 'Action', 'Self', 'S, M (a weapon with which you have proficiency and that is worth 1+ CP)', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'Guided by a flash of magical insight, you make one attack with the weapon used in the spell’s casting. The attack uses your spellcasting ability for the attack and damage rolls instead of using Strength or Dexterity. If the attack deals damage, it can be Radiant damage or the weapon’s normal damage type (your choice).', 'Cantrip Upgrade. Whether you deal Radiant damage or the weapon’s normal damage type, the attack deals extra Radiant damage when you reach levels 5 (1d6), 11 (2d6), and 17 (3d6).', FALSE, ARRAY['artificer', 'bard', 'cantrip', 'divination', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Vicious Mockery', 0, 'Enchantment', 'Action', '60 feet', 'V', 'Instantaneous', 'Player''s Handbook', ARRAY['Bard']::TEXT[], 'You unleash a string of insults laced with subtle enchantments at one creature you can see or hear within range. The target must succeed on a Wisdom saving throw or take 1d6 Psychic damage and have Disadvantage on the next attack roll it makes before the end of its next turn.', 'Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', FALSE, ARRAY['bard', 'cantrip', 'enchantment']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Word of Radiance', 0, 'Evocation', 'Action', 'Self', 'V, M (a sunburst token)', 'Instantaneous', 'Player''s Handbook', ARRAY['Cleric']::TEXT[], 'Burning radiance erupts from you in a 5-foot Emanation. Each creature of your choice that you can see in it must succeed on a Constitution saving throw or take 1d6 Radiant damage.', 'Cantrip Upgrade. The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', FALSE, ARRAY['cantrip', 'cleric', 'evocation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Alarm', 1, 'Abjuration', '1 minute or Ritual', '30 feet', 'V, S, M (a bell and silver wire)', '8 hours', 'Player''s Handbook', ARRAY['Artificer', 'Ranger', 'Wizard']::TEXT[], 'You set an alarm against intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot Cube. Until the spell ends, an alarm alerts you whenever a creature touches or enters the warded area. When you cast the spell, you can designate creatures that won’t set off the alarm. You also choose whether the alarm is audible or mental:

Audible Alarm. The alarm produces the sound of a handbell for 10 seconds within 60 feet of the warded area.

Mental Alarm. You are alerted by a mental ping if you are within 1 mile of the warded area. This ping awakens you if you’re asleep.', NULL, FALSE, ARRAY['abjuration', 'artificer', 'first', 'ranger', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Animal Friendship', 1, 'Enchantment', 'Action', '30 feet', 'V, S, M (a morsel of food)', '24 hours', 'Player''s Handbook', ARRAY['Bard', 'Druid', 'Ranger']::TEXT[], 'Target a Beast that you can see within range. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. If you or one of your allies deals damage to the target, the spells ends.

Using a Higher-Level Spell Slot. You can target one additional Beast for each spell slot level above 1.', NULL, FALSE, ARRAY['bard', 'druid', 'enchantment', 'first', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Armor of Agathys', 1, 'Abjuration', 'Bonus Action', 'Self', 'V, S, M (a shard of blue glass)', '1 Hour', 'Player''s Handbook', ARRAY['Warlock']::TEXT[], 'Protective magical frost surrounds you. You gain 5 Temporary Hit Points. If a creature hits you with a melee attack roll before the spell ends, the creature takes 5 Cold damage. The spell ends early if you have no Temporary Hit Points.

Using a Higher-Level Spell Slot. The Temporary Hit Points and the Cold damage both increase by 5 for each spell slot level above 1.', NULL, FALSE, ARRAY['abjuration', 'first', 'warlock']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Arms of Hadar', 1, 'Conjuration', 'Action', 'Self', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Warlock']::TEXT[], 'Invoking Hadar, you cause tendrils to erupt from yourself. Each creature in a 10-foot Emanation originating from you makes a Strength saving throw. On a failed save, a target takes 2d6 Necrotic damage and can’t take Reactions until the start of its next turn. On a successful save, a target takes half as much damage only.

Using a Higher-Level Spell Slot. The damage increases by 1d6 for each spell slot level above 1.', NULL, FALSE, ARRAY['conjuration', 'first', 'warlock']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Bane', 1, 'Enchantment', 'Action', '30 feet', 'V, S, M (a drop of blood)', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Bard', 'Cleric', 'Warlock']::TEXT[], 'Up to three creatures of your choice that you can see within range must each make a Charisma saving throw. Whenever a target that fails this save makes an attack roll or a saving throw before the spell ends, the target must subtract 1d4 from the attack roll or save.

Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['bard', 'cleric', 'enchantment', 'first', 'warlock']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Bless', 1, 'Enchantment', 'Action', '30 feet', 'V, S, M (a Holy Symbol worth 5+ GP)', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Cleric', 'Paladin']::TEXT[], 'You bless up to three creatures within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target adds 1d4 to the attack roll or save.

Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['cleric', 'enchantment', 'first', 'paladin']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Burning Hands', 1, 'Evocation', 'Action', 'Self', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Sorcerer', 'Wizard']::TEXT[], 'A thin sheet of flames shoots forth from you. Each creature in a 15-foot Cone makes a Dexterity saving throw, taking 3d6 Fire damage on a failed save or half as much damage on a successful one.

Flammable objects in the Cone that aren’t being worn or carried start burning.

Using a Higher-Level Spell Slot. The damage increases by 1d6 for each spell slot level above 1.', NULL, FALSE, ARRAY['evocation', 'first', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Buzzing Bee', 1, 'Conjuration', 'Action', '120 feet.', 'V, S, M (a dab of honey)', 'Concentration, up to 1 minute', 'D&D Beyond Drops - May 2026', ARRAY['Druid', 'Ranger', 'Sorcerer', 'Wizard']::TEXT[], 'You call forth a noisy spectral bee. You target a creature that you can see within range. The bee hovers around the target, distracting it with loud buzzing. For the duration, the target has Disadvantage on Wisdom (Perception) checks, Dexterity (Stealth) checks, and Constitution saving throws made to maintain Concentration. In addition, the target cannot benefit from the Invisible condition.

The bee moves with the target, hovering within 3 feet of it as long as the target is within 120 feet of you. The bee disappears when the spell ends or if the target moves out of range.', NULL, FALSE, ARRAY['conjuration', 'drops', 'drops0526', 'druid', 'first', 'ranger', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Charm Person', 1, 'Enchantment', 'Action', '30 feet', 'V, S', '1 hour', 'Player''s Handbook', ARRAY['Bard', 'Druid', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'One Humanoid you can see within range makes a Wisdom saving throw. It does so with Advantage if you or your allies are fighting it. On a failed save, the target has the Charmed condition until the spell ends or until you or your allies damage it. The Charmed creature is Friendly to you. When the spell ends, the target knows it was Charmed by you.

Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['bard', 'druid', 'enchantment', 'first', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Chromatic Orb', 1, 'Evocation', 'Action', '90 feet', 'V, S, M (a diamond worth 50+ GP)', 'Instantaneous', 'Player''s Handbook', ARRAY['Sorcerer', 'Wizard']::TEXT[], 'You hurl an orb of energy at a target within range. Choose Acid, Cold, Fire, Lightning, Poison, or Thunder for the type of orb you create, and then make a ranged spell attack against the target. On a hit, the target takes 3d8 damage of the chosen type.

If you roll the same number on two or more of the d8s, the orb leaps to a different target of your choice within 30 feet of the target. Make an attack roll against the new target, and make a new damage roll. The orb can’t leap again unless you cast the spell with a level 2+ spell slot.

Using a Higher-Level Spell Slot. The damage increases by 1d8 for each spell slot level above 1. The orb can leap a maximum number of times equal to the level of the slot expended, and a creature can be targeted only once by each casting of this spell.', NULL, FALSE, ARRAY['evocation', 'first', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Color Spray', 1, 'Illusion', 'Action', 'Self', 'V, S, M (a pinch of colorful sand)', 'Instantaneous', 'Player''s Handbook', ARRAY['Bard', 'Sorcerer', 'Wizard']::TEXT[], 'You launch a dazzling array of flashing, colorful light. Each creature in a 15-foot Cone originating from you must succeed on a Constitution saving throw or have the Blinded condition until the end of your next turn.', NULL, FALSE, ARRAY['bard', 'first', 'illusion', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Command', 1, 'Enchantment', 'Action', '60 feet', 'V', 'Instantaneous', 'Player''s Handbook', ARRAY['Bard', 'Cleric', 'Paladin']::TEXT[], 'You speak a one-word command to a creature you can see within range. The target must succeed on a Wisdom saving throw or follow the command on its next turn. Choose the command from these options:

Approach. The target moves toward you by the shortest and most direct route, ending its turn if it moves within 5 feet of you.

Drop. The target drops whatever it is holding and then ends its turn.

Flee. The target spends its turn moving away from you by the fastest available means.

Grovel. The target has the Prone condition and then ends its turn.

Halt. On its turn, the target doesn’t move and takes no action or Bonus Action.

Using a Higher-Level Spell Slot. You can affect one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['bard', 'cleric', 'enchantment', 'first', 'paladin']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Compelled Duel', 1, 'Enchantment', 'Bonus Action', '30 feet', 'V', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Paladin']::TEXT[], 'You try to compel a creature into a duel. One creature that you can see within range makes a Wisdom saving throw. On a failed save, the target has Disadvantage on attack rolls against creatures other than you, and it can''t willingly move to a space that is more than 30 feet away from you.

The spell ends if you make an attack roll against a creature other than the target, if you cast a spell on an enemy other than the target, if an ally of yours damages the target, or if you end your turn more than 30 feet away from the target.', NULL, FALSE, ARRAY['enchantment', 'first', 'paladin']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Cure Wounds', 1, 'Abjuration', 'Action', 'Touch', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Cleric', 'Druid', 'Paladin', 'Ranger']::TEXT[], 'A creature you touch regains a number of Hit Points equal to 2d8 plus your spellcasting ability modifier.

Using a Higher-Level Spell Slot. The healing increases by 2d8 for each spell slot level above 1.', NULL, FALSE, ARRAY['abjuration', 'artificer', 'bard', 'cleric', 'druid', 'first', 'paladin', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Comprehend Languages', 1, 'Divination', 'Action or Ritual', 'Self', 'V, S, M (a pinch of soot and salt)', '1 hour', 'Player''s Handbook', ARRAY['Bard', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'For the duration, you understand the literal meaning of any language that you hear or see signed. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text. This spell doesn''t decode symbols or secret messages.', NULL, FALSE, ARRAY['bard', 'divination', 'first', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Create or Destroy Water', 1, 'Transmutation', 'Action', '30 feet', 'V, S, M (a mix of water and sand)', 'Instantaneous', 'Player''s Handbook', ARRAY['Cleric', 'Druid']::TEXT[], 'You do one of the following:

Create Water. You create up to 10 gallons of clean water within range in an open container. Alternatively, the water falls as rain in a 30-foot Cube within range, extinguishing exposed flames there.

Destroy Water. You destroy up to 10 gallons of water in an open container within range. Alternatively, you destroy fog in a 30-foot Cube within range.

Using a Higher-Level Spell Slot. You create or destroy 10 additional gallons of water, or the size of the Cube increases by 5 feet, for each spell slot level above 1.', NULL, FALSE, ARRAY['cleric', 'druid', 'first', 'transmutation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Detect Evil and Good', 1, 'Divination', 'Action', 'Self', 'V, S', 'Concentration, up to 10 minutes', 'Player''s Handbook', ARRAY['Cleric', 'Paladin']::TEXT[], 'For the duration, you sense the location of any Aberration, Celestial, Elemental, Fey, Fiend, or Undead within 30 feet of yourself. You also sense whether the Hallow spell is active there and, if so, where.

The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.', NULL, FALSE, ARRAY['cleric', 'divination', 'first', 'paladin']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Detect Magic', 1, 'Divination', 'Action or Ritual', 'Self', 'V, S', 'Concentration, up to 10 minutes', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Cleric', 'Druid', 'Paladin', 'Ranger', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'For the duration, you sense the presence of magical effects within 30 feet of yourself. If you sense such effects, you can take the Magic action to see a faint aura around any visible creature or object in the area that bears the magic, and if an effect was created by a spell, you learn the spell''s school of magic.

The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.', NULL, FALSE, ARRAY['artificer', 'bard', 'cleric', 'divination', 'druid', 'first', 'paladin', 'ranger', 'sorcerer', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Disguise Self', 1, 'Illusion', 'Action', 'Self', 'V, S', '1 hour', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Sorcerer', 'Wizard']::TEXT[], 'You make yourself - including your clothing, armor, weapons, and other belongings on your person - look different until the spell ends. You can seem 1 foot shorter or taller and can appear heavier or lighter. You must adopt a form that has the same basic arrangement of limbs as you have. Otherwise, the extent of the illusion is up to you.

The changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing.

To discern that you are disguised, a creature must take the Study action to inspect your appearance and succeed on an Intelligence (Investigation) check against your spell save DC.', NULL, FALSE, ARRAY['artificer', 'bard', 'first', 'illusion', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Dissonant Whispers', 1, 'Enchantment', 'Action', '60 feet', 'V', 'Instantaneous', 'Player''s Handbook', ARRAY['Bard']::TEXT[], 'One creature of your choice that you can see within range hears a discordant melody in its mind. The target makes a Wisdom saving throw. On a failed save, it takes 3d6 Psychic damage and must immediately use its Reaction, if available, to move as far away from you as it can, using the safest route. On a successful save, the target takes half as much damage only.

Using a Higher-Level Spell Slot. The damage increases by 1d6 for each spell slot level above 1.', NULL, FALSE, ARRAY['bard', 'enchantment', 'first']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Detect Poison and Disease', 1, 'Divination', 'Action or Ritual', 'Self', 'V, S, M (a yew leaf)', 'Concentration, up to 10 minutes', 'Player''s Handbook', ARRAY['Cleric', 'Druid', 'Paladin', 'Ranger']::TEXT[], 'For the duration, you sense the location of poisons, poisonous or venomous creatures, and magical contagions within 30 feet of yourself. You sense the kind of poison, creature, or contagion in each case.

The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.', NULL, FALSE, ARRAY['cleric', 'divination', 'druid', 'first', 'paladin', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Divine Favor', 1, 'Transmutation', 'Bonus Action', 'Self', 'V, S', '1 minute', 'Player''s Handbook', ARRAY['Paladin']::TEXT[], 'Until the spell ends, your attacks with weapons deal an extra 1d4 Radiant damage on a hit.', NULL, FALSE, ARRAY['first', 'paladin', 'transmutation']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Divine Smite', 1, 'Evocation', 'Bonus Action, which you take immediately after hitting a target with a Melee weapon or an Unarmed Strike', 'Self', 'V', 'Instantaneous', 'Player''s Handbook', ARRAY['Paladin']::TEXT[], 'The target takes an extra 2d8 Radiant damage from the attack. The damage increases by 1d8 if the target is a Fiend or an Undead.

Using a Higher-Level Spell Slot. The damage increases by 1d8 for each spell slot level above 1.', NULL, FALSE, ARRAY['evocation', 'first', 'paladin']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Ensnaring Strike', 1, 'Conjuration', 'Bonus Action, which you take immediately after hitting a creature with a weapon', 'Self', 'V', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Ranger']::TEXT[], 'As you hit the target, grasping vines appear on it, and it makes a Strength saving throw. A Large or larger creature has Advantage on this save. On a failed save, the target has the Restrained condition until the spell ends. On a successful save, the vines shrivel away, and the spell ends.

While Restrained, the target takes 1d6 Piercing damage at the start of each of its turns. The target or a creature within reach of it can take an action to make a Strength (Athletics) check against your spell save DC. On a success, the spell ends.

Using a Higher-Level Spell Slot. The damage increases by 1d6 for each spell slot level above 1.', NULL, FALSE, ARRAY['conjuration', 'first', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Entangle', 1, 'Conjuration', 'Action', '90 feet', 'V, S', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Druid', 'Ranger']::TEXT[], 'Grasping plants sprout from the ground in a 20-foot square within range. For the duration, these plants turn the ground in the area into Difficult Terrain. They disappear when the spell ends.

Each creature (other than you) in the area when you cast the spell must succeed on a Strength saving throw or have the Restrained condition until the spell ends. A Restrained creature can take an action to make a Strength (Athletics) check against your spell save DC. On a success, it frees itself from the grasping plants and is no longer Restrained by them.', NULL, FALSE, ARRAY['conjuration', 'druid', 'first', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Expeditious Retreat', 1, 'Transmutation', 'Bonus Action', 'Self', 'V, S', 'Concentration, up to 10 minutes', 'Player''s Handbook', ARRAY['Artificer', 'Sorcerer', 'Warlock', 'Wizard']::TEXT[], 'You take the Dash action, and until the spell ends, you can take that action again as a Bonus Action.', NULL, FALSE, ARRAY['artificer', 'first', 'sorcerer', 'transmutation', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Faerie Fire', 1, 'Evocation', 'Action', '60 feet', 'V', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Druid']::TEXT[], 'Objects in a 20-foot Cube within range are outlined in blue, green, or violet light (your choice). Each creature in the Cube is also outlined if it fails a Dexterity saving throw. For the duration, objects and affected creatures shed Dim Light in a 10-foot radius and can’t benefit from the Invisible condition.

Attack rolls against an affected creature or object have Advantage if the attacker can see it.', NULL, FALSE, ARRAY['artificer', 'bard', 'druid', 'evocation', 'first']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('False Life', 1, 'Necromancy', 'Action', 'Self', 'V, S, M (a drop of alcohol)', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Sorcerer', 'Wizard']::TEXT[], 'You gain 2d4 + 4 Temporary Hit Points.

Using a Higher-Level Spell Slot. You gain 5 additional Temporary Hit Points for each spell slot level above 1.', NULL, FALSE, ARRAY['artificer', 'first', 'necromancy', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Feather Fall', 1, 'Transmutation', 'Reaction, which you take when you or a creature you can see within 60 feet of you falls', '60 feet', 'V, M (a small feather or piece of down)', '1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Sorcerer', 'Wizard']::TEXT[], 'Choose up to five falling creatures within range. A falling creature’s rate of descent slows to 60 feet per round until the spell ends. If a creature lands before the spell ends, the creature takes no damage from the fall, and the spell ends for that creature.', NULL, FALSE, ARRAY['artificer', 'bard', 'first', 'sorcerer', 'transmutation', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Find Familiar', 1, 'Conjuration', '1 hour or Ritual', '10 feet', 'V, S, M (burning incense worth 10+ GP, which the spell consumes)', 'Instantaneous', 'Player''s Handbook', ARRAY['Wizard']::TEXT[], 'You gain the service of a familiar, a spirit that takes an animal form you choose: Bat, Cat, Frog, Hawk, Lizard, Octopus, Owl, Rat, Raven, Spider, Weasel, or another Beast that has a Challenge Rating of 0. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form (see appendix B), though it is a Celestial, Fey, or Fiend (your choice) instead of a Beast. Your familiar acts independently of you, but it obeys your commands.

Telepathic Connection. While your familiar is within 100 feet of you, you can communicate with it telepathically. Additionally, as a Bonus Action, you can see through the familiar’s eyes and hear what it hears until the start of your next turn, gaining the benefits of any special senses it has.

Finally, when you cast a spell with a range of touch, your familiar can deliver the touch. Your familiar must be within 100 feet of you, and it must take a Reaction to deliver the touch when you cast the spell.

Combat. The familiar is an ally to you and your allies. It rolls its own Initiative and acts on its own turn. A familiar can’t attack, but it can take other actions as normal.

Disappearance of the Familiar. When the familiar drops to 0 Hit Points, it disappears. It reappears after you cast this spell again. As a Magic action, you can temporarily dismiss the familiar to a pocket dimension. Alternatively, you can dismiss it forever. As a Magic action while it is temporarily dismissed, you can cause it to reappear in an unoccupied space within 30 feet of you. Whenever the familiar drops to 0 Hit Points or disappears into the pocket dimension, it leaves behind in its space anything it was wearing or carrying.

One Familiar Only. You can’t have more than one familiar at a time. If you cast this spell while you have a familiar, you instead cause it to adopt a new eligible form.', NULL, FALSE, ARRAY['conjuration', 'first', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Fog Cloud', 1, 'Conjuration', 'Action', '120 feet', 'V, S', 'Concentration, up to 1 hour', 'Player''s Handbook', ARRAY['Druid', 'Ranger', 'Sorcerer', 'Wizard']::TEXT[], 'You create a 20-foot-radius Sphere of fog centered on a point within range. The Sphere is Heavily Obscured. It lasts for the duration or until a strong wind (such as one created by Gust of Wind) disperses it.

Using a Higher-Level Spell Slot. The fog’s radius increases by 20 feet for each spell slot level above 1.', NULL, FALSE, ARRAY['conjuration', 'druid', 'first', 'ranger', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Goodberry', 1, 'Conjuration', 'Action', 'Self', 'V, S, M (a sprig of mistletoe)', '24 hours', 'Player''s Handbook', ARRAY['Druid', 'Ranger']::TEXT[], 'Ten berries appear in your hand and are infused with magic for the duration. A creature can take a Bonus Action to eat one berry. Eating a berry restores 1 Hit Point, and the berry provides enough nourishment to sustain a creature for one day.

Uneaten berries disappear when the spell ends.', NULL, FALSE, ARRAY['conjuration', 'druid', 'first', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Grease', 1, 'Conjuration', 'Action', '60 feet', 'V, S, M (a bit of pork rind or butter)', '1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Sorcerer', 'Wizard']::TEXT[], 'Nonflammable grease covers the ground in a 10-foot square centered on a point within range and turns it into Difficult Terrain for the duration.

When the grease appears, each creature standing in its area must succeed on a Dexterity saving throw or have the Prone condition. A creature that enters the area or ends its turn there must also succeed on that save or fall Prone.', NULL, FALSE, ARRAY['artificer', 'conjuration', 'first', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Hail of Thorns', 1, 'Conjuration', 'Bonus Action, which you take immediately after hitting a creature with a Ranged weapon', 'Self', 'V', 'Instantaneous', 'Player''s Handbook', ARRAY['Ranger']::TEXT[], 'As you hit the creature, this spell creates a rain of thorns that sprouts from your Ranged weapon or ammunition. The target of the attack and each creature within 5 feet of it make a Dexterity saving throw, taking 1d10 Piercing damage on a failed save or half as much damage on a successful one.

Using a Higher-Level Spell Slot. The damage increases by 1d10 for each spell slot level above 1.', NULL, FALSE, ARRAY['conjuration', 'first', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Guiding Bolt', 1, 'Evocation', 'Action', '120 feet', 'V, S', '1 round', 'Player''s Handbook', ARRAY['Cleric']::TEXT[], 'You hurl a bolt of light toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 4d6 Radiant damage, and the next attack roll made against it before the end of your next turn has Advantage.

Using a Higher-Level Spell Slot. The damage increases by 1d6 for each spell slot level above 1.', NULL, FALSE, ARRAY['cleric', 'evocation', 'first']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Healing Word', 1, 'Abjuration', 'Bonus Action', '60 feet', 'V', 'Instantaneous', 'Player''s Handbook', ARRAY['Bard', 'Cleric', 'Druid']::TEXT[], 'A creature of your choice that you can see within range regains Hit Points equal to 2d4 plus your spellcasting ability modifier.

Using a Higher-Level Spell Slot. The healing increases by 2d4 for each spell slot level above 1.', NULL, FALSE, ARRAY['abjuration', 'bard', 'cleric', 'druid', 'first']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Hellish Rebuke', 1, 'Evocation', 'Reaction, which you take in response to taking damage from a creature that you can see within 60 feet of yourself', '60 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Warlock']::TEXT[], 'The creature that damaged you is momentarily surrounded by green flames. It makes a Dexterity saving throw, taking 2d10 Fire damage on a failed save or half as much damage on a successful one.

Using a Higher-Level Spell Slot. The damage increases by 1d10 for each spell slot level above 1.', NULL, FALSE, ARRAY['evocation', 'first', 'warlock']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Heroism', 1, 'Enchantment', 'Action', 'Touch', 'V, S', 'Concentration, up to 1 minute', 'Player''s Handbook', ARRAY['Bard', 'Paladin']::TEXT[], 'A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to the Frightened condition and gains Temporary Hit Points equal to your spellcasting ability modifier at the start of each of its turns.

Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['bard', 'enchantment', 'first', 'paladin']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Hex', 1, 'Enchantment', 'Bonus Action', '90 feet', 'V, S, M (the petrified eye of a newt)', 'Concentration, up to 1 hour', 'Player''s Handbook', ARRAY['Warlock']::TEXT[], 'You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 Necrotic damage to the target whenever you hit it with an attack roll. Also, choose one ability when you cast the spell. The target has Disadvantage on ability checks made with the chosen ability.

If the target drops to 0 Hit Points before this spell ends, you can take a Bonus Action on a later turn to curse a new creature.

Using a Higher-Level Spell Slot. Your Concentration can last longer with a spell slot of level 2 (up to 4 hours), 3–4 (up to 8 hours), or 5+ (24 hours).', NULL, FALSE, ARRAY['enchantment', 'first', 'warlock']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Hunter''s Mark', 1, 'Divination', 'Bonus Action', '90 feet', 'V', 'Concentration, up to 1 hour', 'Player''s Handbook', ARRAY['Ranger']::TEXT[], 'You magically mark one creature you can see within range as your quarry. Until the spell ends, you deal an extra 1d6 Force damage to the target whenever you hit it with an attack roll. You also have Advantage on any Wisdom (Perception or Survival) check you make to find it.

If the target drops to 0 Hit Points before this spell ends, you can take a Bonus Action to move the mark to a new creature you can see within range.

Using a Higher-Level Spell Slot. Your Concentration can last longer with a spell slot of level 3–4 (up to 8 hours) or 5+ (up to 24 hours).', NULL, FALSE, ARRAY['divination', 'first', 'ranger']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Ice Knife', 1, 'Conjuration', 'Action', '60 feet', 'S, M (a drop of water or a piece of ice)', 'Instantaneous', 'Player''s Handbook', ARRAY['Druid', 'Sorcerer', 'Wizard']::TEXT[], 'You create a shard of ice and fling it at one creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Piercing damage. Hit or miss, the shard then explodes. The target and each creature within 5 feet of it must succeed on a Dexterity saving throw or take 2d6 Cold damage.

Using a Higher-Level Spell Slot. The Cold damage increases by 1d6 for each spell slot level above 1.', NULL, FALSE, ARRAY['conjuration', 'druid', 'first', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Identify', 1, 'Divination', '1 minute or Ritual', 'Touch', 'V, S, M (a pearl worth 100+ GP)', 'Instantaneous', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Wizard']::TEXT[], 'You touch an object throughout the spell’s casting. If the object is a magic item or some other magical object, you learn its properties and how to use them, whether it requires Attunement, and how many charges it has, if any. You learn whether any ongoing spells are affecting the item and what they are. If the item was created by a spell, you learn that spell’s name.

If you instead touch a creature throughout the casting, you learn which ongoing spells, if any, are currently affecting it.', NULL, FALSE, ARRAY['artificer', 'bard', 'divination', 'first', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Inflict Wounds', 1, 'Necromancy', 'Action', 'Touch', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Cleric']::TEXT[], 'A creature you touch makes a Constitution saving throw, taking 2d10 Necrotic damage on a failed save or half as much damage on a successful one.

Using a Higher-Level Spell Slot. The damage increases by 1d10 for each spell slot level above 1.', NULL, FALSE, ARRAY['cleric', 'first', 'necromancy']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Illusory Script', 1, 'Illusion', '1 minute or Ritual', 'Touch', 'S, M (ink worth 10+ GP, which the spell consumes)', '10 days', 'Player''s Handbook', ARRAY['Bard', 'Warlock', 'Wizard']::TEXT[], 'You write on parchment, paper, or another suitable material and imbue it with an illusion that lasts for the duration. To you and any creatures you designate when you cast the spell, the writing appears normal, seems to be written in your hand, and conveys whatever meaning you intended when you wrote the text. To all others, the writing appears as if it were written in an unknown or magical script that is unintelligible. Alternatively, the illusion can alter the meaning, handwriting, and language of the text, though the language must be one you know.

If the spell is dispelled, the original script and the illusion both disappear.

A creature that has Truesight can read the hidden message.', NULL, FALSE, ARRAY['bard', 'first', 'illusion', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Insidious Rhythm', 1, 'Enchantment', 'Action', '120 feet.', 'V, S', 'Concentration, up to 1 minute', 'D&D Beyond Drops - May 2026', ARRAY['Bard']::TEXT[], 'One creature of your choice that you can see within range hears a haunting yet catchy tune that continuously repeats in its mind. The target must succeed on a Wisdom saving throw, or it has Disadvantage on Intelligence checks and on Constitution saving throws made to maintain Concentration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.

Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['bard', 'drops', 'drops0526', 'enchantment', 'first']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Jump', 1, 'Transmutation', 'Bonus Action', 'Touch', 'V, S, M (a grasshopper’s hind leg)', '1 minute', 'Player''s Handbook', ARRAY['Artificer', 'Druid', 'Ranger', 'Sorcerer', 'Wizard']::TEXT[], 'You touch a willing creature. Once on each of its turns until the spell ends, that creature can jump up to 30 feet by spending 10 feet of movement.

Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['artificer', 'druid', 'first', 'ranger', 'sorcerer', 'transmutation', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Longstrider', 1, 'Transmutation', 'Action', 'Touch', 'V, S, M (a pinch of dirt)', '1 hour', 'Player''s Handbook', ARRAY['Artificer', 'Bard', 'Druid', 'Ranger', 'Wizard']::TEXT[], 'You touch a creature. The target’s Speed increases by 10 feet until the spell ends.

Using a Higher-Level Spell Slot. You can target one additional creature for each spell slot level above 1.', NULL, FALSE, ARRAY['artificer', 'bard', 'druid', 'first', 'ranger', 'transmutation', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Mage Armor', 1, 'Abjuration', 'Action', 'Touch', 'V, S, M (a piece of cured leather)', '8 hours', 'Player''s Handbook', ARRAY['Sorcerer', 'Wizard']::TEXT[], 'You touch a willing creature who isn’t wearing armor. Until the spell ends, the target’s base AC becomes 13 plus its Dexterity modifier. The spell ends early if the target dons armor.', NULL, FALSE, ARRAY['abjuration', 'first', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Magic Missile', 1, 'Evocation', 'Action', '120 feet', 'V, S', 'Instantaneous', 'Player''s Handbook', ARRAY['Sorcerer', 'Wizard']::TEXT[], 'You create three glowing darts of magical force. Each dart strikes a creature of your choice that you can see within range. A dart deals 1d4 + 1 Force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.

Using a Higher-Level Spell Slot. The spell creates one more dart for each spell slot level above 1.', NULL, FALSE, ARRAY['evocation', 'first', 'sorcerer', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.spells (name, level, school, casting_time, range, components, duration, source, classes, description, upgrades, legacy, tags) VALUES ('Protection from Evil and Good', 1, 'Abjuration', 'Action', 'Touch', 'V, S, M (a flask of Holy Water worth 25+ GP, which the spell consumes)', 'Concentration up to 10 minutes', 'Player''s Handbook', ARRAY['Cleric', 'Druid', 'Paladin', 'Warlock', 'Wizard']::TEXT[], 'Until the spell ends, one willing creature you touch is protected against creatures that are Aberrations, Celestials, Elementals, Fey, Fiends, or Undead. The protection grants several benefits. Creatures of those types have Disadvantage on attack rolls against the target. The target also can’t be possessed by or gain the Charmed or Frightened conditions from them. If the target is already possessed, Charmed, or Frightened by such a creature, the target has Advantage on any new saving throw against the relevant effect.', NULL, FALSE, ARRAY['abjuration', 'cleric', 'druid', 'first', 'paladin', 'warlock', 'wizard']::TEXT[]) ON CONFLICT (name) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, range = EXCLUDED.range, components = EXCLUDED.components, duration = EXCLUDED.duration, source = EXCLUDED.source, classes = EXCLUDED.classes, description = EXCLUDED.description, upgrades = EXCLUDED.upgrades, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
